import redis
import os
import json
from datetime import timedelta
from typing import Optional, Any

class RedisCache:
    def __init__(self, redis_nodes: list, ssl_enabled: bool = True):
        self.redis_nodes = redis_nodes
        self.ssl_enabled = ssl_enabled
        self.redis_connections = []
        self._connect_to_cluster()
    
    def _connect_to_cluster(self):
        for node in self.redis_nodes:
            try:
                connection = redis.Redis(
                    host=node['host'],
                    port=node['port'],
                    ssl=self.ssl_enabled,
                    ssl_cert_reqs='required' if self.ssl_enabled else None,
                    decode_responses=True,
                    socket_connect_timeout=5,
                    socket_timeout=5,
                    retry_on_timeout=True
                )
                connection.ping()
                self.redis_connections.append(connection)
            except Exception as e:
                print(f"Failed to connect to Redis node {node}: {e}")
    
    def set_session_token(self, user_id: str, token: str, ttl_minutes: int = 30):
        key = f"session:{user_id}"
        try:
            for conn in self.redis_connections:
                conn.setex(key, timedelta(minutes=ttl_minutes), token)
            return True
        except Exception as e:
            print(f"Error setting session token: {e}")
            return False
    
    def get_session_token(self, user_id: str) -> Optional[str]:
        key = f"session:{user_id}"
        try:
            for conn in self.redis_connections:
                token = conn.get(key)
                if token:
                    return token
            return None
        except Exception as e:
            print(f"Error getting session token: {e}")
            return None
    
    def set_api_key(self, user_id: str, api_key: str, ttl_minutes: int = 1440):
        key = f"api_key:{user_id}"
        try:
            for conn in self.redis_connections:
                conn.setex(key, timedelta(minutes=ttl_minutes), api_key)
            return True
        except Exception as e:
            print(f"Error setting API key: {e}")
            return False
    
    def get_api_key(self, user_id: str) -> Optional[str]:
        key = f"api_key:{user_id}"
        try:
            for conn in self.redis_connections:
                key_value = conn.get(key)
                if key_value:
                    return key_value
            return None
        except Exception as e:
            print(f"Error getting API key: {e}")
            return None
    
    def delete_session_token(self, user_id: str):
        key = f"session:{user_id}"
        try:
            for conn in self.redis_connections:
                conn.delete(key)
            return True
        except Exception as e:
            print(f"Error deleting session token: {e}")
            return False
    
    def delete_api_key(self, user_id: str):
        key = f"api_key:{user_id}"
        try:
            for conn in self.redis_connections:
                conn.delete(key)
            return True
        except Exception as e:
            print(f"Error deleting API key: {e}")
            return False

